import React, { useState, useEffect } from 'react';
import './Navbar.css';

export const Navbar = ({ cartCount }) => {
  const [menuAbierto, setMenuAbierto] = useState(false);
  const [busqueda, setBusqueda] = useState('');
  const [dropdownAbierto, setDropdownAbierto] = useState(null);

  const categorias = [
    {
      nombre: 'Laptops', id: 'laptops', href: '#laptops',
      subcategorias: [
        { nombre: 'Para estudiantes', badge: 'Popular', tipo: 'pop' },
        { nombre: 'Para oficina' },
        { nombre: 'Gaming', badge: 'Oferta', tipo: 'off' },
        { nombre: 'Ultradelgadas' },
      ],
      marcas: 'HP · Lenovo · Asus · Dell',
    },
    {
      nombre: 'Monitores', id: 'monitores', href: '#monitores',
      subcategorias: [
        { nombre: 'Full HD' },
        { nombre: '4K' },
        { nombre: 'Gaming 144Hz+', badge: 'Oferta', tipo: 'off' },
        { nombre: 'Curvos' },
      ],
      marcas: 'Samsung · LG · AOC',
    },
    {
      nombre: 'Teclados', id: 'teclados', href: '#teclados',
      subcategorias: [
        { nombre: 'Mecánicos', badge: 'Nuevo', tipo: 'new' },
        { nombre: 'Inalámbricos' },
        { nombre: 'Gaming RGB' },
        { nombre: 'Compactos' },
      ],
    },
    {
      nombre: 'Mouse', id: 'mouse', href: '#mouse',
      subcategorias: [
        { nombre: 'Inalámbrico' },
        { nombre: 'Gaming', badge: 'Oferta', tipo: 'off' },
        { nombre: 'Ergonómico' },
        { nombre: 'Con cable' },
      ],
    },
    {
      nombre: 'Auriculares', id: 'auriculares', href: '#auriculares',
      subcategorias: [
        { nombre: 'Gaming', badge: 'Nuevo', tipo: 'new' },
        { nombre: 'Inalámbricos' },
        { nombre: 'Con micrófono' },
        { nombre: 'In-ear / TWS' },
      ],
    },
  ];

  // Cierra dropdown al hacer clic fuera
  useEffect(() => {
    const handleFuera = (e) => {
      if (!e.target.closest('.cat-item')) setDropdownAbierto(null);
    };
    document.addEventListener('mousedown', handleFuera);
    return () => document.removeEventListener('mousedown', handleFuera);
  }, []);

  const toggleDropdown = (id) => {
    setDropdownAbierto(dropdownAbierto === id ? null : id);
  };

  const handleBusqueda = (e) => {
    e.preventDefault();
    console.log('Buscando:', busqueda);
  };

  // Clase del badge según tipo
  const badgeClass = (tipo) => {
    if (tipo === 'pop') return 'badge badge-pop';
    if (tipo === 'new') return 'badge badge-new';
    return 'badge badge-off';
  };

  return (
    <header>
      {/* Barra de promociones */}
      <div className="promo-bar">
        Envío gratis en Lima desde S/ 199
        <span className="promo-sep">|</span>
        Hasta 12 cuotas sin intereses
        <span className="promo-sep">|</span>
        Garantía oficial 12 meses
      </div>

      {/* Navbar principal */}
      <nav className="navbar">
        <a href="#inicio" className="navbar-logo">
          Tech<span>Store</span>
        </a>

        <form className="navbar-search" onSubmit={handleBusqueda}>
          <input
            type="text"
            placeholder="Buscar laptops, monitores, teclados..."
            value={busqueda}
            onChange={(e) => setBusqueda(e.target.value)}
          />
          <button type="submit" aria-label="Buscar">
            <svg viewBox="0 0 24 24" fill="none" stroke="#0a1929" strokeWidth="2.5" strokeLinecap="round">
              <circle cx="11" cy="11" r="7"/><path d="M21 21l-4.35-4.35"/>
            </svg>
          </button>
        </form>

        <div className="navbar-acciones">
          <a href="#cuenta" className="btn-cuenta">
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.8">
              <path d="M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2"/>
              <circle cx="12" cy="7" r="4"/>
            </svg>
            Mi cuenta
          </a>
          <a href="#carrito" className="btn-carrito">
            <svg viewBox="0 0 24 24" fill="none" stroke="#0a1929" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <path d="M6 2L3 6v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2V6l-3-4z"/>
              <line x1="3" y1="6" x2="21" y2="6"/>
              <path d="M16 10a4 4 0 0 1-8 0"/>
            </svg>
            Carrito
            {cartCount > 0 && <span className="badge-carrito">{cartCount}</span>}
          </a>
        </div>

        <button
          className="navbar-hamburguesa"
          onClick={() => setMenuAbierto(!menuAbierto)}
          aria-label="Abrir menú"
        >
          ☰
        </button>
      </nav>

      {/* Barra de categorías */}
      <div className={`navbar-cats ${menuAbierto ? 'abierto' : ''}`}>
        <ul className="cats-list">

          {categorias.map((cat) => (
            <li key={cat.id} className="cat-item">
              <button
                className={`cat-btn ${dropdownAbierto === cat.id ? 'active' : ''}`}
                onClick={() => toggleDropdown(cat.id)}
              >
                {cat.nombre}
                <span className={`chevron ${dropdownAbierto === cat.id ? 'open' : ''}`}>▾</span>
              </button>

              {dropdownAbierto === cat.id && (
                <ul className="dropdown">
                  {cat.subcategorias.map((sub) => (
                    <li key={sub.nombre}>
                      <a href={cat.href} onClick={() => setDropdownAbierto(null)}>
                        {sub.nombre}
                        {sub.badge && (
                          <span className={badgeClass(sub.tipo)}>{sub.badge}</span>
                        )}
                      </a>
                    </li>
                  ))}
                  {cat.marcas && (
                    <>
                      <li className="dropdown-sep" />
                      <li>
                        <a href={cat.href} className="dropdown-marcas" onClick={() => setDropdownAbierto(null)}>
                          {cat.marcas}
                        </a>
                      </li>
                    </>
                  )}
                </ul>
              )}
            </li>
          ))}

          <li className="cat-item">
            <a href="#ofertas" className="cat-btn">Ofertas</a>
          </li>
          <li className="cat-item">
            <a href="#remates" className="cat-btn cat-remates">🔥 Remates</a>
          </li>

        </ul>
      </div>
    </header>
  );
};
